import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Test Postbacks","description":"","frontmatter":{"title":"Test Postbacks","slug":"testing-postbacks"},"headers":[],"relativePath":"marketer-hub/testing-postbacks.md","filePath":"marketer-hub/testing-postbacks.md"}'),i={name:"marketer-hub/testing-postbacks.md"};function s(r,e,l,h,p,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Testing your configuration is a very important step that we highly recommend you take the time to complete before going live with marketing campaigns.</p><p>The following guide walks you through how to ensure Postbacks are correctly firing to your ad partner and passing all of the relevant data.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to test postbacks, you need to have completed the following:</p><ol><li>Completed the <a href="./ad-partner-integration-guide.html">Ad Partner Integration Guide</a>.</li><li>Added a <a href="./add-test-devices.html">Test Device</a> to your Branch Dashboard.</li></ol><h2 id="selecting-your-test-platform" tabindex="-1">Selecting Your Test Platform <a class="header-anchor" href="#selecting-your-test-platform" aria-label="Permalink to &quot;Selecting Your Test Platform&quot;">​</a></h2><p>In order to properly test the postbacks set up for your ad partner, you must first select the platform - Web Browser or Mobile App - on which you will be testing. Your selection impacts both the test link generated in the next step, as well as items shown during the test.</p><ol><li><p>In the left-hand navigation, under <strong>Channels &amp; Links</strong>, click on <strong>Ads</strong> and then <strong>Partner Management</strong>.</p></li><li><p>Select the appropriate Ad Partner and click on the <strong>Postback Testing</strong> tab.</p></li><li><p>Select either <strong>Web (browser)</strong> or <strong>Mobile App</strong>.</p><ul><li>If you select <strong>Mobile App</strong>, also select your test device from the drop-down.</li></ul></li><li><p>Click <strong>Save &amp; Continue</strong>.</p></li></ol><h2 id="link-creation-usage" tabindex="-1">Link Creation &amp; Usage <a class="header-anchor" href="#link-creation-usage" aria-label="Permalink to &quot;Link Creation &amp; Usage&quot;">​</a></h2><p>Based on your selections, Branch creates a test link with all of the necessary information appended to allow you to fully test functionality.</p><p>To use your test link, Copy/Paste the Branch Ad Link to yourself (ex. send it to yourself via Slack).</p><p>Once you have your test link, click <strong>Test</strong>.</p><p>After you click the <strong>Test</strong> button, click the link on the device and perform the event you want to test.</p><h2 id="viewing-test-results" tabindex="-1">Viewing Test Results <a class="header-anchor" href="#viewing-test-results" aria-label="Permalink to &quot;Viewing Test Results&quot;">​</a></h2><p>Once you click the Branch test link provided in the steps above, Branch measures and attributes the click and resulting events. As this happens, these events are displayed in a timeline on the screen in real time.</p><p>For each event Branch measures, the following related data points are viewable. For each postback Branch fires, the following information is available:</p><ul><li>Response Status</li><li>Response Time (in milliseconds)</li><li>Request Timestamp</li><li>Request URL</li><li>Request Method</li><li>Event Data (see previous itemized list)</li></ul><h4 id="what-to-look-for-when-validating" tabindex="-1">What to Look For When Validating <a class="header-anchor" href="#what-to-look-for-when-validating" aria-label="Permalink to &quot;What to Look For When Validating&quot;">​</a></h4><ul><li>Check the expected macros are populated AND the response code. Most importantly, you&#39;ll want to verify the IDFA/AAID and the Click ID are populated.</li><li>We recommend verifying the event with the ad partner even when the Response Code is 200 (successful). To do so, send them the event name, the postback request URL, device ID, timestamp, postback response code and response body.</li><li>If you can’t find the postback you’re looking for, we recommend testing your ad link several more times to trigger the subsequent postback.</li></ul><h2 id="stopping-and-restarting-testing" tabindex="-1">Stopping and Restarting Testing <a class="header-anchor" href="#stopping-and-restarting-testing" aria-label="Permalink to &quot;Stopping and Restarting Testing&quot;">​</a></h2><p>By default, once you click <strong>Test</strong>, Branch will listen for the resulting events for 10 minutes.</p><p>You can choose to stop the testing at any time by clicking <strong>End Postback Testing</strong> in the upper right-hand corner.</p><p>You can also restart the testing at any time by clicking <strong>Start Postback Testing</strong> in the upper right-hand corner.</p>',24)])])}const g=t(i,[["render",s]]);export{u as __pageData,g as default};
